import java.io.*;
import java.util.*;
import java.util.stream.*;

public class Main {
    private static int majorityElement(int[] arr) {
        int candidate = arr[0];
        int count = 1;
        for (int i = 1; i < arr.length; i++) {
            if (arr[i] == candidate) {
                count++;
            } else {
                count--;
                if (count == 0) {
                    candidate = arr[i];
                    count = 1;
                }
            }
        }
        return candidate;
    }

    public static void main(String[] args) throws Exception {
        // Read entire input as a single string
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String data = br.lines().collect(Collectors.joining("\n"));
        // Replace literal "\n" sequences with actual newlines to handle escaped inputs
        data = data.replace("\\n", "\n");
        Scanner sc = new Scanner(data);
        StringBuilder sb = new StringBuilder();
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[] arr = new int[n];
            for (int i = 0; i < n; i++) {
                arr[i] = sc.nextInt();
            }
            sb.append(majorityElement(arr)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

